import React, { useState } from 'react';
import { PageHeader, Modal } from '../../components/UI';

// BASE : https://media.musclewiki.com/media/uploads/videos/branded/
const BASE = 'https://media.musclewiki.com/media/uploads/videos/branded/';
const POSTER = 'https://media.musclewiki.com/media/uploads/';

const muscles = [
  {
    id: 1, nom: 'Biceps', icon: 'bi-lightning-charge', zone: 'Bras',
    video: `${BASE}male-Machine-machine-bicep-curl-front.mp4`,
    poster: `${POSTER}og-male-Machine-machine-bicep-curl-front.jpg`,
    exercices: [
      {
        nom: 'Curl barre', series: '4×10',
        desc: 'Debout, barre en supination. Fléchir les coudes jusqu\'à la hauteur des épaules sans bouger les coudes.',
        video: `${BASE}male-Barbell-barbell-curl-front.mp4`,
        poster: `${POSTER}og-male-Barbell-barbell-curl-front.jpg`,
      },
      {
        nom: 'Curl haltères alternés', series: '3×12',
        desc: 'Alterner gauche-droite en contrôlant la descente. Tourner le poignet en haut du mouvement.',
        video: `${BASE}male-Dumbbells-dumbbell-curl-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-curl-front.jpg`,
      },
      {
        nom: 'Curl marteau', series: '3×12',
        desc: 'Prise neutre (pouce vers le haut). Cible aussi le brachial et l\'avant-bras.',
        video: `${BASE}male-Dumbbells-dumbbell-hammer-curl-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-hammer-curl-front.jpg`,
      },
      {
        nom: 'Curl concentré', series: '3×15',
        desc: 'Assis, coude appuyé sur la cuisse. Excellent pour le pic du biceps.',
        video: `${BASE}male-Dumbbells-dumbbell-concentration-curl-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-concentration-curl-front.jpg`,
      },
    ]
  },
  {
    id: 2, nom: 'Triceps', icon: 'bi-lightning', zone: 'Bras',
    video: `${BASE}male-cables-cable-rope-pushdown-front.mp4`,
    poster: `${POSTER}og-male-cables-cable-rope-pushdown-front.jpg`,
    exercices: [
      {
        nom: 'Dips', series: '4×12',
        desc: 'Corps vertical, coudes près du corps. Plus efficace avec lest quand maîtrisé.',
        video: `${BASE}male-Bodyweight-parralel-bar-dips-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-parralel-bar-dips-front.jpg`,
      },
      {
        nom: 'Extension nuque', series: '3×12',
        desc: 'Haltère ou barre EZ derrière la tête. Cible le chef long du triceps.',
        video: `${BASE}male-Dumbbells-dumbbell-overhead-tricep-extension-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-overhead-tricep-extension-front.jpg`,
      },
      {
        nom: 'Pushdown câble', series: '4×15',
        desc: 'Câble haute poulie, coudes fixes. Excellent pour la finition et le pump.',
        video: `${BASE}male-cables-cable-rope-pushdown-front.mp4`,
        poster: `${POSTER}og-male-cables-cable-rope-pushdown-front.jpg`,
      },
      {
        nom: 'Pompes diamant', series: '3×15',
        desc: 'Mains en triangle sous le sternum. Variante au poids du corps très efficace.',
        video: `${BASE}male-Bodyweight-diamond-push-up-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-diamond-push-up-front.jpg`,
      },
    ]
  },
  {
    id: 3, nom: 'Pectoraux', icon: 'bi-person-arms-up', zone: 'Buste',
    video: `${BASE}male-Machine-machine-chest-press-front.mp4`,
    poster: `${POSTER}og-male-Machine-machine-chest-press-front.jpg`,
    exercices: [
      {
        nom: 'Développé couché', series: '5×8',
        desc: 'Le roi des exercices de poitrine. Descendre la barre jusqu\'à effleurer le sternum.',
        video: `${BASE}male-Barbell-barbell-bench-press-front.mp4`,
        poster: `${POSTER}og-male-Barbell-barbell-bench-press-front.jpg`,
      },
      {
        nom: 'Développé incliné', series: '4×10',
        desc: 'Banc à 30-45°. Cible le faisceau supérieur pour un pec plus complet.',
        video: `${BASE}male-Barbell-barbell-incline-bench-press-front.mp4`,
        poster: `${POSTER}og-male-Barbell-barbell-incline-bench-press-front.jpg`,
      },
      {
        nom: 'Écarté haltères', series: '3×12',
        desc: 'Légère flexion des coudes. Mouvement d\'isolation, descente lente et contrôlée.',
        video: `${BASE}male-Dumbbells-dumbbell-fly-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-fly-front.jpg`,
      },
      {
        nom: 'Crossover câbles', series: '3×15',
        desc: 'Croisement des mains en bas. Étirement maximal du grand pectoral.',
        video: `${BASE}male-cables-cable-crossover-front.mp4`,
        poster: `${POSTER}og-male-cables-cable-crossover-front.jpg`,
      },
    ]
  },
  {
    id: 4, nom: 'Dos', icon: 'bi-arrows-expand-vertical', zone: 'Dos',
    video: `${BASE}male-Machine-machine-pulldown-front.mp4`,
    poster: `${POSTER}og-male-Machine-machine-pulldown-front.jpg`,
    exercices: [
      {
        nom: 'Tractions', series: '4×8',
        desc: 'Prise large pronation. Le squat du dos. Ajouter du lest progressivement.',
        video: `${BASE}male-Bodyweight-pull-up-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-pull-up-front.jpg`,
      },
      {
        nom: 'Rowing barre', series: '4×10',
        desc: 'Tronc parallèle au sol, tirer vers le nombril. Excellent pour l\'épaisseur.',
        video: `${BASE}male-Barbell-barbell-row-front.mp4`,
        poster: `${POSTER}og-male-Barbell-barbell-row-front.jpg`,
      },
      {
        nom: 'Tirage poulie haute', series: '3×12',
        desc: 'Tirer vers le haut du sternum. Alternatif aux tractions pour les débutants.',
        video: `${BASE}male-Machine-machine-pulldown-front.mp4`,
        poster: `${POSTER}og-male-Machine-machine-pulldown-front.jpg`,
      },
      {
        nom: 'Soulevé de terre', series: '4×6',
        desc: 'Le mouvement roi. Dos droit, gainage total, poussée des talons dans le sol.',
        video: `${BASE}male-Barbell-barbell-deadlift-front.mp4`,
        poster: `${POSTER}og-male-Barbell-barbell-deadlift-front.jpg`,
      },
    ]
  },
  {
    id: 5, nom: 'Épaules', icon: 'bi-award', zone: 'Épaules',
    video: `${BASE}male-Machine-machine-shoulder-press-front.mp4`,
    poster: `${POSTER}og-male-Machine-machine-shoulder-press-front.jpg`,
    exercices: [
      {
        nom: 'Développé militaire', series: '4×10',
        desc: 'Debout ou assis, barre ou haltères. Cible le faisceau antérieur en priorité.',
        video: `${BASE}male-Barbell-barbell-overhead-press-front.mp4`,
        poster: `${POSTER}og-male-Barbell-barbell-overhead-press-front.jpg`,
      },
      {
        nom: 'Élévation latérale', series: '4×15',
        desc: 'Petits poids, coudes légèrement fléchis. Faisceau latéral = épaules larges.',
        video: `${BASE}male-Dumbbells-dumbbell-lateral-raise-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-lateral-raise-front.jpg`,
      },
      {
        nom: 'Oiseau (Rear delt)', series: '3×15',
        desc: 'Tronc penché, bras en croix. Indispensable pour équilibrer posture et force.',
        video: `${BASE}male-Dumbbells-dumbbell-reverse-fly-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-reverse-fly-front.jpg`,
      },
      {
        nom: 'Shrugs', series: '4×12',
        desc: 'Haussement d\'épaules avec haltères ou barre. Cible les trapèzes supérieurs.',
        video: `${BASE}male-Dumbbells-dumbbell-shrug-front.mp4`,
        poster: `${POSTER}og-male-Dumbbells-dumbbell-shrug-front.jpg`,
      },
    ]
  },
  {
    id: 6, nom: 'Jambes', icon: 'bi-activity', zone: 'Jambes',
    video: `${BASE}male-Machine-machine-leg-press-front.mp4`,
    poster: `${POSTER}og-male-Machine-machine-leg-press-front.jpg`,
    exercices: [
      {
        nom: 'Squat', series: '5×8',
        desc: 'Le roi des exercices. Descendre cuisses parallèles, dos droit, genoux dans l\'axe.',
        video: `${BASE}male-Barbell-barbell-squat-front.mp4`,
        poster: `${POSTER}og-male-Barbell-barbell-squat-front.jpg`,
      },
      {
        nom: 'Presse à cuisses', series: '4×12',
        desc: 'Pieds hauts = ischios/fessiers. Pieds bas = quadriceps. Contrôler la montée.',
        video: `${BASE}male-Machine-machine-leg-press-front.mp4`,
        poster: `${POSTER}og-male-Machine-machine-leg-press-front.jpg`,
      },
      {
        nom: 'Fentes marchées', series: '3×10',
        desc: 'Chaque jambe. Grand pas, genou avant à 90°. Excellent pour l\'équilibre.',
        video: `${BASE}male-Bodyweight-bodyweight-lunge-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-bodyweight-lunge-front.jpg`,
      },
      {
        nom: 'Leg extension', series: '3×15',
        desc: 'Isolation quadriceps. Finition en fin de séance pour le pump.',
        video: `${BASE}male-Machine-machine-leg-extension-front.mp4`,
        poster: `${POSTER}og-male-Machine-machine-leg-extension-front.jpg`,
      },
      {
        nom: 'Leg curl', series: '3×15',
        desc: 'Isolation ischios-jambiers. Ne pas négliger les muscles postérieurs.',
        video: `${BASE}male-Machine-seated-leg-curl-front.mp4`,
        poster: `${POSTER}og-male-Machine-seated-leg-curl-front.jpg`,
      },
    ]
  },
  {
    id: 7, nom: 'Abdominaux', icon: 'bi-grid-3x3', zone: 'Core',
    video: `${BASE}male-bodyweight-crunch-front.mp4`,
    poster: `${POSTER}og-male-bodyweight-crunch-front.jpg`,
    exercices: [
      {
        nom: 'Gainage planche', series: '4×60s',
        desc: 'Corps aligné, contractez abdos et fessiers. Base indispensable du gainage.',
        video: `${BASE}male-Bodyweight-plank-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-plank-front.jpg`,
      },
      {
        nom: 'Crunch câble', series: '4×20',
        desc: 'Plus efficace que le crunch classique car résistance constante sur tout le mouvement.',
        video: `${BASE}male-cables-cable-crunch-front.mp4`,
        poster: `${POSTER}og-male-cables-cable-crunch-front.jpg`,
      },
      {
        nom: 'Relevé de jambes', series: '3×15',
        desc: 'Suspendu ou allongé. Cible le bas du ventre (droit inférieur).',
        video: `${BASE}male-Bodyweight-hanging-leg-raise-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-hanging-leg-raise-front.jpg`,
      },
      {
        nom: 'Russian twist', series: '3×20',
        desc: 'Avec médecine-ball ou haltère. Cible les obliques et la rotation du tronc.',
        video: `${BASE}male-Bodyweight-russian-twist-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-russian-twist-front.jpg`,
      },
    ]
  },
  {
    id: 8, nom: 'Mollets', icon: 'bi-arrow-up-circle', zone: 'Jambes',
    video: `${BASE}male-bodyweight-standing-calf-raise-front.mp4`,
    poster: `${POSTER}og-male-bodyweight-standing-calf-raise-front.jpg`,
    exercices: [
      {
        nom: 'Extensions mollets debout', series: '5×20',
        desc: 'Amplitude complète, tenir 1s en haut. Les mollets récupèrent vite, volume élevé.',
        video: `${BASE}male-Bodyweight-standing-calf-raise-front.mp4`,
        poster: `${POSTER}og-male-Bodyweight-standing-calf-raise-front.jpg`,
      },
      {
        nom: 'Extensions assis', series: '4×20',
        desc: 'Cible le soléaire (muscle profond). Indispensable pour des mollets complets.',
        video: `${BASE}male-Machine-machine-seated-calf-raise-front.mp4`,
        poster: `${POSTER}og-male-Machine-machine-seated-calf-raise-front.jpg`,
      },
    ]
  },
];

// Composant vidéo — boucle auto comme un GIF
function ExerciseVideo({ src, poster, style = {} }) {
  return (
    <video
      key={src}
      src={src}
      poster={poster}
      autoPlay
      loop
      muted
      playsInline
      style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block', ...style }}
    />
  );
}

export default function Musculation() {
  const [selected, setSelected] = useState(null);
  const [activeExo, setActiveExo] = useState(null); // exercice actif dans la modale

  // Quand on ouvre un muscle, reset l'exercice actif
  const openMuscle = (m) => {
    setSelected(m);
    setActiveExo(null);
  };

  // Vidéo affichée en haut de la modale
  const displayedVideo = activeExo?.video ?? selected?.video;
  const displayedPoster = activeExo?.poster ?? selected?.poster;

  return (
    <div>
      <PageHeader eyebrow="Guide d'entraînement" title="Exercices par" accent="Groupe Musculaire" />

      <div style={{ padding: '16px 28px 8px', fontSize: 13, color: 'var(--text-muted)' }}>
        Cliquez sur un groupe musculaire pour voir les exercices recommandés, les séries et les conseils techniques.
      </div>

      {/* Grille des muscles */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 14, padding: '12px 28px 32px' }}>
        {muscles.map(m => (
          <div
            key={m.id}
            className="fz-card hoverable"
            style={{ overflow: 'hidden', padding: 0 }}
            onClick={() => openMuscle(m)}
          >
            <div className="muscle-img-placeholder" style={{ position: 'relative', overflow: 'hidden' }}>
              <ExerciseVideo src={m.video} poster={m.poster} />
            </div>
            <div style={{ padding: '12px 14px' }}>
              <div style={{ fontFamily: 'var(--font-heading)', fontSize: 16, fontWeight: 700, marginBottom: 2 }}>{m.nom}</div>
              <div style={{ fontSize: 10, color: 'var(--text-dim)', marginBottom: 8 }}>{m.zone} · {m.exercices.length} exercices</div>
              {m.exercices.slice(0, 2).map(e => (
                <div key={e.nom} style={{ fontSize: 11, color: 'var(--text-muted)', marginBottom: 2 }}>
                  <i className="bi bi-chevron-right me-1" style={{ fontSize: 9, color: 'var(--red)' }}></i>{e.nom}
                </div>
              ))}
              <div style={{ fontSize: 10, color: 'var(--text-dim)', marginTop: 4 }}>+{m.exercices.length - 2} autres...</div>
            </div>
          </div>
        ))}
      </div>

      {/* Modale détail muscle */}
      <Modal show={!!selected} title={selected?.nom} onClose={() => setSelected(null)} size="lg">
        {selected && (
          <div>
            {/* Header badges */}
            <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap', alignItems: 'center' }}>
              <span className="fz-badge type">{selected.zone}</span>
              <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{selected.exercices.length} exercices</span>
              {activeExo && (
                <span style={{ fontSize: 11, color: 'var(--red)', marginLeft: 'auto', cursor: 'pointer' }}
                  onClick={() => setActiveExo(null)}>
                  ← Revenir au groupe
                </span>
              )}
            </div>

            {/* Vidéo principale — change selon l'exercice cliqué */}
            <div style={{
              marginBottom: 20, borderRadius: 10, border: '1px solid var(--border)',
              height: 240, overflow: 'hidden', background: '#111', position: 'relative'
            }}>
              <ExerciseVideo
                src={displayedVideo}
                poster={displayedPoster}
                style={{ objectFit: 'contain', background: '#111' }}
              />
              {/* Label de l'exercice actif */}
              {activeExo && (
                <div style={{
                  position: 'absolute', bottom: 0, left: 0, right: 0,
                  background: 'linear-gradient(transparent, rgba(0,0,0,0.8))',
                  padding: '20px 14px 10px',
                  fontSize: 13, fontWeight: 700, color: '#fff',
                  fontFamily: 'var(--font-heading)'
                }}>
                  {activeExo.nom}
                </div>
              )}
            </div>

            {/* Liste exercices — cliquables */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {selected.exercices.map((e) => {
                const isActive = activeExo?.nom === e.nom;
                return (
                  <div
                    key={e.nom}
                    onClick={() => setActiveExo(isActive ? null : e)}
                    style={{
                      background: isActive ? 'var(--surface3, #2a2a2a)' : 'var(--surface2)',
                      borderRadius: 10,
                      padding: '14px 16px',
                      borderLeft: `3px solid ${isActive ? 'var(--red)' : 'var(--red)'}`,
                      cursor: 'pointer',
                      transition: 'all 0.15s ease',
                      outline: isActive ? '1px solid var(--red)' : '1px solid transparent',
                    }}
                  >
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 6 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                        {/* Icône play/pause */}
                        <div style={{
                          width: 22, height: 22, borderRadius: '50%',
                          background: isActive ? 'var(--red)' : 'rgba(255,255,255,0.08)',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          flexShrink: 0, transition: 'background 0.15s'
                        }}>
                          <i className={`bi bi-${isActive ? 'pause-fill' : 'play-fill'}`}
                            style={{ fontSize: 9, color: isActive ? '#fff' : 'var(--red)', marginLeft: isActive ? 0 : 1 }}></i>
                        </div>
                        <div style={{ fontFamily: 'var(--font-heading)', fontSize: 15, fontWeight: 700 }}>{e.nom}</div>
                      </div>
                      <span className="fz-badge type">{e.series}</span>
                    </div>
                    <p style={{ fontSize: 12, color: 'var(--text-muted)', margin: 0, lineHeight: 1.6, paddingLeft: 30 }}>
                      {e.desc}
                    </p>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
